import React, { useState, useEffect, createContext, useContext } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, Navigate, useNavigate } from 'react-router-dom';
import './App.css';

const API_BASE = 'http://localhost:3001/api';

// Helper to get full image URL
const getImageUrl = (path) => {
  if (!path) return null;
  if (path.startsWith('http')) return path;
  return `http://localhost:3001${path}`;
};

// API helper
const api = {
  get: async (endpoint) => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE}${endpoint}`, {
      headers: { 'Authorization': `Bearer ${token}` }
    });
    return res.json();
  },
  post: async (endpoint, data) => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE}${endpoint}`, {
      method: 'POST',
      headers: { 
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}` 
      },
      body: JSON.stringify(data)
    });
    return res.json();
  },
  put: async (endpoint, data) => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE}${endpoint}`, {
      method: 'PUT',
      headers: { 
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}` 
      },
      body: JSON.stringify(data)
    });
    return res.json();
  },
  delete: async (endpoint) => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE}${endpoint}`, {
      method: 'DELETE',
      headers: { 'Authorization': `Bearer ${token}` }
    });
    return res.json();
  }
};

// Auth Context
const AuthContext = createContext(null);
const useAuth = () => useContext(AuthContext);

// Login Page
function LoginPage() {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await fetch(`${API_BASE}/auth/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username, password })
      });
      const data = await res.json();
      if (data.success) {
        login(data.token, data.user);
        navigate('/');
      } else {
        setError(data.message || 'Login failed');
      }
    } catch (err) {
      setError('Connection error');
    }
  };

  return (
    <div className="login-page">
      <div className="login-container">
        <div className="login-header">
          <div className="login-logo">
            <svg viewBox="0 0 100 100" className="logo-svg">
              <circle cx="50" cy="50" r="45" fill="#1a365d" stroke="#2c5282" strokeWidth="2"/>
              <path d="M50 20 L50 80 M30 40 L50 20 L70 40" stroke="#fff" strokeWidth="4" fill="none" strokeLinecap="round" strokeLinejoin="round"/>
              <circle cx="50" cy="55" r="15" stroke="#2c5282" strokeWidth="2" fill="none"/>
            </svg>
          </div>
          <h1>Sanaduk Saving and Credit Cooperative Ltd.</h1>
          <p>Member Management System</p>
        </div>
        <form onSubmit={handleSubmit}>
          <input type="text" placeholder="Username" value={username} onChange={e => setUsername(e.target.value)} required />
          <input type="password" placeholder="Password" value={password} onChange={e => setPassword(e.target.value)} required />
          {error && <div className="error">{error}</div>}
          <button type="submit" className="btn-primary">Login</button>
        </form>
        <p className="login-hint">Default: admin / admin123</p>
      </div>
    </div>
  );
}

// Dashboard Page
function Dashboard() {
  const [stats, setStats] = useState({ members: 0, loans: 0, shares: 0, savings: 0 });
  const [recentMembers, setRecentMembers] = useState([]);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [membersRes, loansRes, sharesRes, savingsRes] = await Promise.all([
          api.get('/members'),
          api.get('/loans'),
          api.get('/shares'),
          api.get('/savings')
        ]);
        setStats({
          members: (membersRes.data || membersRes || []).length,
          loans: (loansRes.data || loansRes || []).length,
          shares: (sharesRes.data || sharesRes || []).length,
          savings: (savingsRes.data || savingsRes || []).length
        });
        const members = membersRes.data || membersRes || [];
        setRecentMembers(members.slice(-5).reverse());
      } catch (error) {
        console.error('Error fetching stats:', error);
      }
    };
    fetchData();
  }, []);

  return (
    <div className="dashboard">
      <div className="page-header">
        <h1>Dashboard</h1>
        <p>Welcome to Sanaduk Saving and Credit Cooperative Ltd.</p>
      </div>
      
      <div className="intro-section">
        <h2>About Our Cooperative</h2>
        <p>Sanaduk Saving and Credit Cooperative Ltd. is dedicated to providing financial services to our community. We offer savings accounts, loans, and share investments to help our members achieve their financial goals.</p>
      </div>

      <div className="stats-grid">
        <div className="stat-card">
          <div className="stat-icon">👥</div>
          <div className="stat-info">
            <h3>{stats.members}</h3>
            <p>Total Members</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">💰</div>
          <div className="stat-info">
            <h3>{stats.loans}</h3>
            <p>Active Loans</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">📊</div>
          <div className="stat-info">
            <h3>{stats.shares}</h3>
            <p>Share Holders</p>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">🏦</div>
          <div className="stat-info">
            <h3>{stats.savings}</h3>
            <p>Savings Accounts</p>
          </div>
        </div>
      </div>

      {recentMembers.length > 0 && (
        <div className="recent-section">
          <h2>Recent Members</h2>
          <div className="table-container">
            <table className="data-table">
              <thead>
                <tr>
                  <th>Member No.</th>
                  <th>Name</th>
                  <th>Phone</th>
                  <th>Type</th>
                  <th>Joined Date</th>
                </tr>
              </thead>
              <tbody>
                {recentMembers.map(m => (
                  <tr key={m.id}>
                    <td>{m.member_number}</td>
                    <td>{m.member_name}</td>
                    <td>{m.phone}</td>
                    <td>{m.membership_type}</td>
                    <td>{m.joined_date || '-'}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}

// Members Page
function MembersPage() {
  const [members, setMembers] = useState([]);
  const [filter, setFilter] = useState('');
  const [form, setForm] = useState({
    member_name: '', address: '', phone: '', email: '', 
    joined_date: '', membership_type: 'Saving', status: 'Active'
  });
  const [editingId, setEditingId] = useState(null);

  useEffect(() => { fetchMembers(); }, []);

  const fetchMembers = async () => {
    try {
      const response = await api.get('/members');
      const membersData = response.data || response || [];
      setMembers(Array.isArray(membersData) ? membersData : []);
    } catch (error) {
      console.error('Error fetching members:', error);
      setMembers([]);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (editingId) {
      await api.put(`/members/${editingId}`, form);
    } else {
      await api.post('/members', form);
    }
    fetchMembers();
    resetForm();
  };

  const handleEdit = (member) => {
    setForm(member);
    setEditingId(member.id);
  };

  const handleDelete = async (id) => {
    if (window.confirm('Delete this member?')) {
      await api.delete(`/members/${id}`);
      fetchMembers();
    }
  };

  const resetForm = () => {
    setForm({
      member_name: '', address: '', phone: '', email: '', 
      joined_date: '', membership_type: 'Saving', status: 'Active'
    });
    setEditingId(null);
  };

  const filteredMembers = members.filter(m => 
    m && (m.member_name || '').toLowerCase().includes((filter || '').toLowerCase()) ||
    m && (m.member_number || '').toLowerCase().includes((filter || '').toLowerCase()) ||
    m && (m.phone || '').toLowerCase().includes((filter || '').toLowerCase())
  );

  return (
    <div className="members-page">
      <div className="page-header">
        <h1>Members Management</h1>
        <p>Add, view, edit, and manage cooperative members</p>
      </div>
      <div className="form-section">
        <h2>{editingId ? 'Edit Member' : 'Add New Member'}</h2>
        <form onSubmit={handleSubmit}>
          <div className="form-row">
            <input type="text" placeholder="Full Name *" value={form.member_name} onChange={e => setForm({...form, member_name: e.target.value})} required />
            <input type="text" placeholder="Address" value={form.address} onChange={e => setForm({...form, address: e.target.value})} />
          </div>
          <div className="form-row">
            <input type="text" placeholder="Phone *" value={form.phone} onChange={e => setForm({...form, phone: e.target.value})} required />
            <input type="email" placeholder="Email" value={form.email} onChange={e => setForm({...form, email: e.target.value})} />
            <input type="text" placeholder="Joined Date (BS) e.g., 2080-05-15" value={form.joined_date} onChange={e => setForm({...form, joined_date: e.target.value})} />
          </div>
          <div className="form-row">
            <select value={form.membership_type} onChange={e => setForm({...form, membership_type: e.target.value})}>
              <option value="Saving">Saving</option>
              <option value="Loan">Loan</option>
              <option value="Share">Share</option>
            </select>
            <select value={form.status} onChange={e => setForm({...form, status: e.target.value})}>
              <option value="Active">Active</option>
              <option value="Inactive">Inactive</option>
            </select>
          </div>
          <div style={{ display: 'flex', gap: '12px', marginTop: '10px' }}>
            <button type="submit" className="btn-primary">{editingId ? 'Update' : 'Add Member'}</button>
            {editingId && <button type="button" onClick={resetForm}>Cancel</button>}
          </div>
        </form>
      </div>
      <div className="filter-bar">
        <input type="text" placeholder="Search members..." value={filter} onChange={e => setFilter(e.target.value)} />
      </div>
      <div className="table-container">
        <table className="data-table">
          <thead>
            <tr>
              <th>Member No.</th>
              <th>Name</th>
              <th>Phone</th>
              <th>Type</th>
              <th>Joined Date</th>
              <th>Status</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {filteredMembers.map(m => (
              <tr key={m.id}>
                <td>{m.member_number}</td>
                <td>{m.member_name}</td>
                <td>{m.phone}</td>
                <td>{m.membership_type}</td>
                <td>{m.joined_date || '-'}</td>
                <td><span className={`status-badge ${(m.status || '').toLowerCase()}`}>{m.status}</span></td>
                <td>
                  <button className="btn-sm" onClick={() => handleEdit(m)}>Edit</button>
                  <button className="btn-sm btn-danger" onClick={() => handleDelete(m.id)}>Delete</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// Loan Page
function LoanPage() {
  const [loans, setLoans] = useState([]);
  const [members, setMembers] = useState([]);
  const [filter, setFilter] = useState('');
  const [form, setForm] = useState({
    member_id: '', loan_type: 'Personal', 
    principal_amount: '', interest_rate: '12', loan_term_months: '12',
    loan_started_date_bs: '', status: 'Active',
    guarantor_name: '', guarantor_phone: ''
  });
  const [editingId, setEditingId] = useState(null);

  useEffect(() => { fetchLoans(); fetchMembers(); }, []);

  const fetchLoans = async () => {
    try {
      const response = await api.get('/loans');
      const loansData = response.data?.data || response.data || response || [];
      setLoans(Array.isArray(loansData) ? loansData : []);
    } catch (error) {
      console.error('Error fetching loans:', error);
      setLoans([]);
    }
  };

  const fetchMembers = async () => {
    try {
      const response = await api.get('/members');
      const membersData = response.data || response || [];
      setMembers(Array.isArray(membersData) ? membersData : []);
    } catch (error) {
      console.error('Error fetching members:', error);
      setMembers([]);
    }
  };

  const getMemberName = (id) => {
    const member = members.find(m => m.id == id);
    return member ? member.member_name : 'Unknown';
  };

  const [viewingLoan, setViewingLoan] = useState(null);

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingId) {
        await api.put(`/loans/${editingId}`, form);
      } else {
        await api.post('/loans', form);
      }
      fetchLoans();
      resetForm();
    } catch (error) {
      console.error('Error saving loan:', error);
      alert('Failed to save loan: ' + (error.response?.data?.error || error.message));
    }
  };

  const handleView = (loan) => {
    setViewingLoan(loan);
  };

  const handleEdit = (loan) => {
    setForm(loan);
    setEditingId(loan.id);
    setViewingLoan(null);
  };

  const handleDelete = async (id) => {
    if (window.confirm('Delete this loan?')) {
      await api.delete(`/loans/${id}`);
      fetchLoans();
    }
  };

  const resetForm = () => {
    setForm({
      member_id: '', loan_type: 'Personal', 
      principal_amount: '', interest_rate: '12', loan_term_months: '12',
