      </div>
      <div className="filter-bar">
        <input type="text" placeholder="Search shares..." value={filter} onChange={e => setFilter(e.target.value)} />
      </div>
      <div className="table-container">
        <table className="data-table">
          <thead>
            <tr>
              <th>Share #</th>
              <th>Member</th>
              <th>Type</th>
              <th>Shares</th>
              <th>Value</th>
              <th>Date (BS)</th>
